1	/**
2	 * Top-level orchestrator page for the onboarding flow. Uses `useOnboarding`
3	 * to get the derived stage, then picks a `stageContent` and a `composer`
4	 * for that stage. Stage-driven swapping keeps each stage's logic isolated;
5	 * shared transcript + progress chrome live in `OnboardingShell` /
6	 * `MessagesRegion`. `skipAutoRedirect` keeps the chat stage rendered here
7	 * instead of redirecting into the standalone `/c/:id` route.
8	 */
9	
10	"use client";
11	
12	import { AnimatePresence } from "motion/react";
13	import * as m from "motion/react-m";
14	import { useState } from "react";
15	import { CompletedStagesTimeline } from "@/features/onboarding/components/CompletedStagesTimeline";
16	import { MessagesRegion } from "@/features/onboarding/components/MessagesRegion";
17	import { OnboardingIntro } from "@/features/onboarding/components/OnboardingIntro";
18	import { OnboardingShell } from "@/features/onboarding/components/OnboardingShell";
19	import {
20	  Chat,
21	  ChatComposer,
22	  FocusComposer,
23	  Platforms,
24	  PlatformsComposer,
25	  QuestionsComposer,
26	  RevealTodos,
27	  RevealWritingStyle,
28	  RevealWritingStyleComposer,
29	  useChatStage,
30	  Workflows,
31	  WorkflowsComposer,
32	} from "@/features/onboarding/components/stages";
33	import { EASE_OUT_QUART } from "@/features/onboarding/constants/motion";
34	import { useOnboarding } from "@/features/onboarding/hooks/useOnboarding";
35	import { useUserStore } from "@/stores/userStore";
36	
37	const INTRO_FADE_IN = {
38	  initial: { opacity: 0, filter: "blur(12px)" },
39	  animate: { opacity: 1, filter: "blur(0px)" },
40	  transition: { duration: 0.6, ease: EASE_OUT_QUART },
41	} as const;
42	
43	const INTRO_SEEN_PREFIX = "gaia.onboarding.introSeen";
44	
45	// Keyed per-user so a new account still gets the intro, while the same
46	// user reloading (or coming back from an external OAuth redirect that lands
47	// them in a fresh browsing context, e.g. Arc's Little Arc) skips it.
48	function introSeenKey(userId: string): string | null {
49	  return userId ? `${INTRO_SEEN_PREFIX}.${userId}` : null;
50	}
51	
52	function hasSeenIntro(userId: string): boolean {
53	  if (typeof window === "undefined") return false;
54	  const key = introSeenKey(userId);
55	  if (!key) return false;
56	  try {
57	    return window.localStorage.getItem(key) === "1";
58	  } catch {
59	    return false;
60	  }
61	}
62	
63	function markIntroSeen(userId: string): void {
64	  const key = introSeenKey(userId);
65	  if (!key) return;
66	  try {
67	    window.localStorage.setItem(key, "1");
68	  } catch {
69	    // localStorage unavailable (private mode, etc.) — silently skip.
70	  }
71	}
72	
73	function clearIntroSeen(userId: string): void {
74	  const key = introSeenKey(userId);
75	  if (!key) return;
76	  try {
77	    window.localStorage.removeItem(key);
78	  } catch {}
79	}
80	
81	export default function Onboarding() {
82	  const { state, stage, dispatch, restart } = useOnboarding({
83	    skipAutoRedirect: true,
84	  });
85	  const userId = useUserStore((s) => s.userId);
86	  const [introDone, setIntroDone] = useState<boolean>(() =>
87	    hasSeenIntro(userId),
88	  );
89	
90	  const handleRestart = () => {
91	    clearIntroSeen(userId);
92	    setIntroDone(false);
93	    return restart();
94	  };
95	
96	  const handleIntroComplete = () => {
97	    markIntroSeen(userId);
98	    setIntroDone(true);
99	  };
100	
101	  const chat = useChatStage(state, dispatch);
102	
103	  const stageContent = (() => {
104	    switch (stage) {
105	      case "questions":
106	      case "focus":
107	      case "processing":
108	        return null;
109	      case "revealWriting":
110	        return <RevealWritingStyle state={state} />;
111	      case "revealTodos":
112	        return <RevealTodos state={state} dispatch={dispatch} chat={chat} />;
113	      case "workflows":
114	        return <Workflows state={state} dispatch={dispatch} />;
115	      case "platforms":
116	        return <Platforms state={state} dispatch={dispatch} />;
117	      case "chat":
118	        return <Chat state={state} />;
119	    }
120	  })();
121	
122	  const composer = (() => {
123	    switch (stage) {
124	      case "questions":
125	        return <QuestionsComposer state={state} dispatch={dispatch} />;
126	      case "focus":
127	        return <FocusComposer state={state} dispatch={dispatch} />;
128	      case "processing":
129	        return null;
130	      case "revealWriting":
131	        return <RevealWritingStyleComposer state={state} dispatch={dispatch} />;
132	      case "revealTodos":
133	        return null;
134	      case "workflows":
135	        return <WorkflowsComposer state={state} dispatch={dispatch} />;
136	      case "platforms":
137	        return <PlatformsComposer state={state} dispatch={dispatch} />;
138	      case "chat":
139	        return <ChatComposer state={state} />;
140	    }
141	  })();
142	
143	  const wrappedComposer = introDone ? (
144	    <m.div {...INTRO_FADE_IN}>{composer}</m.div>
145	  ) : null;
146	
147	  return (
148	    <>
149	      <OnboardingShell
150	        state={state}
151	        stage={stage}
152	        onRestart={handleRestart}
153	        composer={wrappedComposer}
154	      >
155	        {introDone ? (
156	          <m.div {...INTRO_FADE_IN}>
157	            <MessagesRegion state={state} stage={stage} />
158	            <CompletedStagesTimeline
159	              state={state}
160	              dispatch={dispatch}
161	              chat={chat}
162	            />
163	            {stageContent}
164	          </m.div>
165	        ) : null}
166	      </OnboardingShell>
167	      <AnimatePresence>
168	        {!introDone && <OnboardingIntro onComplete={handleIntroComplete} />}
169	      </AnimatePresence>
170	    </>
171	  );
172	}
