1	/**
2	 * `chat` stage. Renders the welcome conversation stream followed by the holo
3	 * card reveal. The composer is always a "Continue to GAIA" CTA — the onboarding
4	 * first message intentionally closes its own loop, so there is no free-chat
5	 * input here. Active once the backend has produced `first_message_conversation_id`.
6	 */
7	
8	"use client";
9	
10	import { Mail01Icon } from "@icons";
11	import * as m from "motion/react-m";
12	import type { Dispatch } from "react";
13	import { useEffect } from "react";
14	import ChatBubbleBot from "@/features/chat/components/bubbles/bot/ChatBubbleBot";
15	import ChatBubbleUser from "@/features/chat/components/bubbles/user/ChatBubbleUser";
16	import { LoadingIndicator } from "@/features/chat/components/interface/LoadingIndicator";
17	import {
18	  BOT_BUBBLE_DEFAULTS,
19	  USER_BUBBLE_DEFAULTS,
20	} from "../../constants/bubbleDefaults";
21	import {
22	  MOTION_COMPOSER_CTA,
23	  MOTION_FADE_UP_LARGE,
24	  MOTION_STREAM_MESSAGE,
25	} from "../../constants/motion";
26	import {
27	  type UseOnboardingChatReturn,
28	  useOnboardingChat,
29	} from "../../hooks/useOnboardingChat";
30	import type { Action, OnboardingState } from "../../state/types";
31	import { OnboardingCTAButton } from "../OnboardingCTAButton";
32	import { HoloCardReveal } from "../reveal/HoloCardReveal";
33	
34	interface ChatProps {
35	  state: OnboardingState;
36	  dispatch: Dispatch<Action>;
37	  chat: UseOnboardingChatReturn;
38	}
39	
40	/**
41	 * Shared hook the page calls once per render so Content and Composer read
42	 * from the same chat stream. Also clears the pending todo execution message
43	 * once the conversation is wired so a remount can't re-queue it. The
44	 * underlying `useOnboardingChat` already dedups the actual send.
45	 */
46	export function useChatStage(
47	  state: OnboardingState,
48	  dispatch: Dispatch<Action>,
49	): UseOnboardingChatReturn {
50	  const conversationId = state.server?.first_message_conversation_id ?? null;
51	  const pendingTodoMessage = state.todoExecutionMessage;
52	
53	  const chat = useOnboardingChat(conversationId, pendingTodoMessage);
54	
55	  useEffect(() => {
56	    if (!pendingTodoMessage || !conversationId) return;
57	    dispatch({ type: "clearTodoExecutionMessage" });
58	  }, [pendingTodoMessage, conversationId, dispatch]);
59	
60	  return chat;
61	}
62	
63	const RUN_NOW_PREFIX = "Execute this todo for me: ";
64	
65	interface TodoRunNowCardProps {
66	  title: string;
67	  sourceEmail: { sender: string; subject: string } | null;
68	}
69	
70	/**
71	 * Custom user-side bubble shown in place of the raw "Execute this todo for me:
72	 * X" auto-send. Surfaces the todo title prominently and the source email as
73	 * a small hint chip below — so the user sees a meaningful card instead of a
74	 * machine-generated sentence.
75	 */
76	function TodoRunNowCard({ title, sourceEmail }: TodoRunNowCardProps) {
77	  return (
78	    <div className="flex justify-end pr-2">
79	      <div className="max-w-[80%] rounded-2xl bg-zinc-800 p-4">
80	        <div className="text-xs font-medium tracking-wide text-zinc-400 uppercase">
81	          Run now
82	        </div>
83	        <div className="mt-1 text-sm text-zinc-100">{title}</div>
84	        {sourceEmail && (
85	          <div className="mt-3 flex items-start gap-2 rounded-xl bg-zinc-900 p-3">
86	            <Mail01Icon className="mt-0.5 size-3.5 shrink-0 text-zinc-500" />
87	            <div className="min-w-0 flex-1">
88	              <div className="truncate text-xs text-zinc-400">
89	                {sourceEmail.sender}
90	              </div>
91	              <div className="truncate text-xs text-zinc-500">
92	                {sourceEmail.subject}
93	              </div>
94	            </div>
95	          </div>
96	        )}
97	      </div>
98	    </div>
99	  );
100	}
101	
102	/** Shared stream renderer — used by both the in-place todo demo inside
103	 *  `revealTodos` and by the final `chat` stage. When a user message matches
104	 *  the Run Now auto-send shape, render the custom `TodoRunNowCard` instead
105	 *  of the raw text bubble. */
106	export function OnboardingChatStream({
107	  chat,
108	  todoOverride,
109	}: {
110	  chat: UseOnboardingChatReturn;
111	  todoOverride?: TodoRunNowCardProps | null;
112	}) {
113	  const runNowStart = chat.streamMessages.findIndex(
114	    (m) =>
115	      m.role === "user" &&
116	      typeof m.content === "string" &&
117	      m.content.startsWith(RUN_NOW_PREFIX),
118	  );
119	  const visibleMessages =
120	    todoOverride && runNowStart >= 0
121	      ? chat.streamMessages.slice(runNowStart)
122	      : chat.streamMessages;
123	  return (
124	    <>
125	      {visibleMessages.map((msg) => {
126	        const isRunNowMessage =
127	          msg.role === "user" &&
128	          typeof msg.content === "string" &&
129	          msg.content.startsWith(RUN_NOW_PREFIX);
130	        return (
131	          <m.div key={msg.id} {...MOTION_STREAM_MESSAGE}>
132	            {msg.role === "user" ? (
133	              isRunNowMessage && todoOverride ? (
134	                <TodoRunNowCard
135	                  title={todoOverride.title}
136	                  sourceEmail={todoOverride.sourceEmail}
137	                />
138	              ) : (
139	                <ChatBubbleUser
140	                  {...USER_BUBBLE_DEFAULTS}
141	                  text={msg.content}
142	                  message_id={msg.id}
143	                  date={msg.createdAt.toISOString()}
144	                  fileData={msg.fileData}
145	                />
146	              )
147	            ) : (
148	              <ChatBubbleBot
149	                {...BOT_BUBBLE_DEFAULTS}
150	                text={msg.content}
151	                message_id={msg.id}
152	                loading={msg.status === "sending"}
153	                tool_data={msg.tool_data ?? undefined}
154	                todo_progress={msg.todo_progress ?? undefined}
155	                memory_data={msg.memory_data ?? undefined}
156	                image_data={msg.image_data ?? undefined}
157	                date={msg.createdAt.toISOString()}
158	              />
159	            )}
160	          </m.div>
161	        );
162	      })}
163	
164	      {chat.isChatSending &&
165	        !visibleMessages.some(
166	          (msg) => msg.role === "assistant" && msg.content,
167	        ) && (
168	          <LoadingIndicator
169	            loadingText={
170	              todoOverride ? "Auto-executing todo…" : "GAIA is thinking…"
171	            }
172	            loadingTextKey={0}
173	          />
174	        )}
175	    </>
176	  );
177	}
178	
179	export function Chat({ state }: Omit<ChatProps, "dispatch" | "chat">) {
180	  const showHolo = state.server?.has_personalization && state.server;
181	  if (!showHolo || !state.server) return null;
182	
183	  const firstMessage = state.server.first_message;
184	
185	  return (
186	    <m.div className="mt-4 space-y-4" {...MOTION_FADE_UP_LARGE}>
187	      {firstMessage && (
188	        <ChatBubbleBot
189	          {...BOT_BUBBLE_DEFAULTS}
190	          text={firstMessage}
191	          message_id="onboarding-first-message"
192	          loading={false}
193	          date={new Date().toISOString()}
194	        />
195	      )}
196	      <div className="my-4">
197	        <HoloCardReveal personalizationData={state.server} />
198	      </div>
199	    </m.div>
200	  );
201	}
202	
203	/** Composer for the `chat` stage. Always renders the "Continue to GAIA" CTA —
204	 *  the onboarding chat stage ends with a closed-loop message (no question), so
205	 *  the user's only forward move is into the full chat experience. The CTA
206	 *  lands the user inside the seeded welcome conversation when available so
207	 *  the post-onboarding welcome UI shows up immediately. */
208	export function ChatComposer({ state }: Omit<ChatProps, "dispatch" | "chat">) {
209	  const welcomeConvoId = state.server?.first_message_conversation_id;
210	  const href = welcomeConvoId ? `/c/${welcomeConvoId}` : "/c";
211	  return (
212	    <m.div className="flex justify-center pb-2" {...MOTION_COMPOSER_CTA}>
213	      <OnboardingCTAButton href={href}>Continue to GAIA</OnboardingCTAButton>
214	    </m.div>
215	  );
216	}
217

