1	/**
2	 * Top-level orchestrator hook for the onboarding flow. Wires the reducer to
3	 * every effect (persistence, OAuth, Gmail auto-advance, submission, backend
4	 * sync, phase, analytics, auto-redirect) and exposes the derived stage plus
5	 * a `restart` action that wipes local state and asks the server to reset.
6	 */
7	
8	"use client";
9	
10	import { useRouter } from "next/navigation";
11	import { useCallback, useEffect, useReducer, useRef } from "react";
12	
13	import type { UserInfo } from "@/features/auth/api/authApi";
14	import { useUser, useUserActions } from "@/features/auth/hooks/useUser";
15	import { userInfoToStoreUser } from "@/features/auth/utils/userInfoToStoreUser";
16	import { db as chatDb } from "@/lib/db/chatDb";
17	import { toast } from "@/lib/toast";
18	import { useChatStore } from "@/stores/chatStore";
19	
20	import { resetOnboarding } from "../api/onboardingApi";
21	import { questions } from "../constants";
22	import { useBackendSync } from "../effects/useBackendSync";
23	import { useGmailAutoAdvance } from "../effects/useGmailAutoAdvance";
24	import { useOAuthCallback } from "../effects/useOAuthCallback";
25	import { useOnboardingAnalytics } from "../effects/useOnboardingAnalytics";
26	import { useOnboardingPersistence } from "../effects/useOnboardingPersistence";
27	import { useOnboardingSubmission } from "../effects/useOnboardingSubmission";
28	import { usePhaseSync } from "../effects/usePhaseSync";
29	import { getStage } from "../state/derive";
30	import { initialState } from "../state/initial";
31	import { clearPersisted } from "../state/persist";
32	import { reducer } from "../state/reducer";
33	import type { Action, OnboardingState, Stage } from "../state/types";
34	
35	interface UseOnboardingReturn {
36	  state: OnboardingState;
37	  stage: Stage;
38	  dispatch: React.Dispatch<Action>;
39	  restart: () => Promise<void>;
40	}
41	
42	interface UseOnboardingArgs {
43	  skipAutoRedirect?: boolean;
44	}
45	
46	/**
47	 * Returns `{ state, stage, dispatch, restart }`. If the authed user already
48	 * completed the onboarding submission server-side (per `user.onboarding`)
49	 * but hasn't reached chat yet, this hook resumes them past the Q&A so a
50	 * post-clear reload doesn't drop them back on Q1. Pass `skipAutoRedirect`
51	 * to keep them on this page when chat is reached (used by the page itself
52	 * which renders the chat stage inline).
53	 *
54	 * `restart` clears persisted state, dispatches `restartStart`, drops the
55	 * old conversation from chat store + IndexedDB, then calls the server
56	 * `/reset` endpoint. The reducer is locked via `isRestarting` until done.
57	 */
58	export function useOnboarding({
59	  skipAutoRedirect = false,
60	}: UseOnboardingArgs = {}): UseOnboardingReturn {
61	  const router = useRouter();
62	  const user = useUser();
63	  const { setUser, updateUser } = useUserActions();
64	  const [state, dispatch] = useReducer(reducer, initialState);
65	  const stage = getStage(state);
66	
67	  // Persist + hydrate from sessionStorage
68	  useOnboardingPersistence(state, dispatch);
69	
70	  // Resume mid-pipeline if backend says onboarding was already submitted but
71	  // hasn't reached chat. Without this, a user reloading after the
72	  // sessionStorage was cleared would land back on Q1. The `questionIndex`
73	  // guard naturally short-circuits subsequent runs once we've hydrated past
74	  // the Q&A — no ref needed.
75	  useEffect(() => {
76	    if (state.questionIndex >= questions.length) return;
77	    if (state.isRestarting) return;
78	    const onboarding = user.onboarding;
79	    if (!onboarding?.completed) return;
80	    if (onboarding.phase === "completed") return;
81	    dispatch({
82	      type: "hydrate",
83	      partial: { questionIndex: questions.length },
84	    });
85	  }, [user.onboarding, state.questionIndex, state.isRestarting]);
86	
87	  // Auto-advance Gmail if integration shows connected on reload
88	  useGmailAutoAdvance(state, dispatch);
89	
90	  // Handle ?oauth_success / ?oauth_error from URL
91	  useOAuthCallback(dispatch);
92	
93	  // Submit POST /onboarding when responses complete and pipeline hasn't started
94	  const handleSubmissionSuccess = useCallback(
95	    (info: UserInfo) => {
96	      setUser(userInfoToStoreUser(info));
97	    },
98	    [setUser],
99	  );
100	  useOnboardingSubmission(state, handleSubmissionSuccess);
101	
102	  // WS + initial snapshot fetch
103	  useBackendSync(state, stage, dispatch);
104	
105	  // POST /onboarding/phase once when entering chat stage
106	  usePhaseSync(stage);
107	
108	  // Analytics
109	  useOnboardingAnalytics(state);
110	
111	  // Auto-redirect into the live chat once the conversation is ready
112	  const redirectedRef = useRef(false);
113	  useEffect(() => {
114	    if (skipAutoRedirect) return;
115	    if (redirectedRef.current) return;
116	    if (stage !== "chat") return;
117	    const conversationId = state.server?.first_message_conversation_id;
118	    if (!conversationId) return;
119	    redirectedRef.current = true;
120	    router.push(`/c/${conversationId}`);
121	  }, [
122	    stage,
123	    state.server?.first_message_conversation_id,
124	    skipAutoRedirect,
125	    router,
126	  ]);
127	
128	  // Restart: optimistic local reset + backend /reset in background
129	  const restart = useCallback(async () => {
130	    if (state.isRestarting) return;
131	
132	    const oldConversationId = state.server?.first_message_conversation_id;
133	
134	    clearPersisted();
135	    dispatch({ type: "restartStart" });
136	    updateUser({ onboarding: undefined });
137	
138	    if (oldConversationId) {
139	      useChatStore.getState().removeConversation(oldConversationId);
140	      void chatDb
141	        .deleteConversationAndMessages(oldConversationId)
142	        .catch((error: unknown) => {
143	          console.error(
144	            "Failed to delete onboarding conversation from IndexedDB:",
145	            error,
146	          );
147	        });
148	    }
149	
150	    redirectedRef.current = false;
151	
152	    try {
153	      await resetOnboarding();
154	    } catch (error) {
155	      console.error("Failed to reset onboarding on server:", error);
156	      toast.error(
157	        "We reset locally, but the server reset didn't fully complete.",
158	      );
159	    } finally {
160	      dispatch({ type: "restartDone" });
161	    }
162	  }, [
163	    state.isRestarting,
164	    state.server?.first_message_conversation_id,
165	    updateUser,
166	  ]);
167	
168	  return { state, stage, dispatch, restart };
169	}
