1	"use client";
2	
3	import { useEffect, useRef } from "react";
4	
5	import type { UserInfo } from "@/features/auth/api/authApi";
6	
7	import { completeOnboarding } from "../api/onboardingApi";
8	import { FIELD_NAMES } from "../constants";
9	import { isResponsesComplete } from "../state/derive";
10	import type { OnboardingState } from "../state/types";
11	
12	/**
13	 * Fires POST /onboarding once all required answers are captured and the
14	 * pipeline hasn't started yet. Idempotent via an in-flight ref.
15	 */
16	export function useOnboardingSubmission(
17	  state: OnboardingState,
18	  onSuccess?: (user: UserInfo) => void,
19	): void {
20	  const inFlightRef = useRef(false);
21	
22	  useEffect(() => {
23	    if (inFlightRef.current) return;
24	    if (state.isRestarting) return;
25	    if (state.server != null) return;
26	    if (!isResponsesComplete(state)) return;
27	
28	    inFlightRef.current = true;
29	    const responses = state.responses;
30	    const body = {
31	      name: responses[FIELD_NAMES.NAME]?.trim() ?? "",
32	      profession: responses[FIELD_NAMES.PROFESSION] ?? "",
33	      timezone: Intl.DateTimeFormat().resolvedOptions().timeZone,
34	      focus: responses[FIELD_NAMES.FOCUS] ?? "",
35	    };
36	
37	    completeOnboarding(body)
38	      .then((response) => {
39	        if (response?.success && response.user) {
40	          onSuccess?.(response.user);
41	        }
42	      })
43	      .catch(() => {
44	        // Submission failed; processing stage stays as-is.
45	      })
46	      .finally(() => {
47	        inFlightRef.current = false;
48	      });
49	  }, [state, onSuccess]);
50	}
