1	/**
2	 * Linear stage cursor. The flow is a fixed queue of stages; the user
3	 * advances forward only, never sideways. Each stage has two checks:
4	 *
5	 * - `isStageReady` — does the backend have the data for this stage yet?
6	 * - `isStageDone`  — is the user past this stage (either acked, or the
7	 *   backend told us there is nothing to show here)?
8	 *
9	 * `getStage` walks the queue once and returns the first stage that is not
10	 * done. If that stage isn't ready, we render `processing` instead of
11	 * skipping ahead — this is what prevents an out-of-order event from
12	 * teleporting the user to a later stage.
13	 *
14	 * The queue is picked once from `hasGmail`: the no-Gmail branch literally
15	 * has no writing-style reveal, so we don't include it.
16	 */
17	
18	import { FIELD_NAMES, questions } from "../constants";
19	import type { OnboardingStage } from "../types/websocket";
20	import type { OnboardingState, Stage } from "./types";
21	
22	export function hasGmail(s: OnboardingState): boolean {
23	  return s.responses[FIELD_NAMES.GMAIL] === "connected";
24	}
25	
26	/**
27	 * The user skipped Gmail and hasn't yet answered the synthetic focus
28	 * question — the no-Gmail branch needs this hint before it can run.
29	 */
30	export function needsFocus(s: OnboardingState): boolean {
31	  return (
32	    s.responses[FIELD_NAMES.GMAIL] === "skipped" &&
33	    s.responses[FIELD_NAMES.FOCUS] == null
34	  );
35	}
36	
37	/** All required answers (incl. focus when Gmail is skipped) are captured. */
38	export function isResponsesComplete(s: OnboardingState): boolean {
39	  return s.questionIndex >= questions.length && !needsFocus(s);
40	}
41	
42	const GMAIL_QUEUE: readonly Stage[] = [
43	  "revealWriting",
44	  "revealTodos",
45	  "workflows",
46	  "platforms",
47	  "chat",
48	];
49	
50	const NO_GMAIL_QUEUE: readonly Stage[] = [
51	  "revealTodos",
52	  "workflows",
53	  "platforms",
54	  "chat",
55	];
56	
57	/**
58	 * True iff the backend has emitted the payload the stage needs to render.
59	 * Stages with no data dependency (`platforms`) are always ready.
60	 */
61	function isStageReady(s: OnboardingState, stage: Stage): boolean {
62	  // `platforms` has no data dependency — always reachable once the cursor
63	  // gets there, even before the initial REST snapshot lands.
64	  if (stage === "platforms") return true;
65	  const b = s.server;
66	  if (!b) return false;
67	  switch (stage) {
68	    case "revealWriting":
69	      return !!b.writing_style?.style_summary;
70	    case "revealTodos":
71	      return (b.onboarding_todos?.length ?? 0) > 0;
72	    case "workflows":
73	      return (b.suggested_workflows?.length ?? 0) > 0;
74	    case "chat":
75	      return !!b.first_message_conversation_id;
76	    default:
77	      return false;
78	  }
79	}
80	
81	/**
82	 * True iff the cursor should move past this stage. Either the user has
83	 * acted on it, or the backend has told us there's nothing here to show
84	 * (the matching `*_ready` event landed without any payload data).
85	 *
86	 * `revealWriting` also waits for `revealTodos` to be ready before being
87	 * marked done — that preserves the "Looking for things I can help with…"
88	 * holding block on the writing-style card after the user clicks "Looks
89	 * good" but before the todos data has arrived.
90	 */
91	function isStageDone(s: OnboardingState, stage: Stage): boolean {
92	  const b = s.server;
93	  switch (stage) {
94	    case "revealWriting": {
95	      if (s.ackedWritingStyle && isStageReady(s, "revealTodos")) return true;
96	      // Backend confirmed there's no style to show (LLM failure).
97	      if (
98	        s.completedStages.has("writing_style_ready") &&
99	        !b?.writing_style?.style_summary
100	      ) {
101	        return true;
102	      }
103	      return false;
104	    }
105	    case "revealTodos": {
106	      if (s.ackedTodos) return true;
107	      // Backend confirmed there are no todos to show.
108	      if (
109	        s.completedStages.has("todos_ready") &&
110	        !b?.onboarding_todos?.length
111	      ) {
112	        return true;
113	      }
114	      return false;
115	    }
116	    case "workflows": {
117	      if (s.workflowsConfirmed) return true;
118	      // Backend confirmed there are no workflows to show.
119	      if (
120	        s.completedStages.has("workflows_ready") &&
121	        !b?.suggested_workflows?.length
122	      ) {
123	        return true;
124	      }
125	      return false;
126	    }
127	    case "platforms":
128	      return s.platformsConfirmed;
129	    case "chat":
130	      return false;
131	    default:
132	      return false;
133	  }
134	}
135	
136	/**
137	 * Resolves the stage the page should render right now. Walks the user's
138	 * linear queue (gmail vs no-gmail), returning the first stage that isn't
139	 * done. If that stage's data isn't ready, returns `processing` so the
140	 * spinner / progress checklist takes over until the event arrives.
141	 */
142	export function getStage(s: OnboardingState): Stage {
143	  if (s.questionIndex < questions.length) return "questions";
144	  if (needsFocus(s)) return "focus";
145	
146	  const queue = hasGmail(s) ? GMAIL_QUEUE : NO_GMAIL_QUEUE;
147	
148	  for (const stage of queue) {
149	    if (isStageDone(s, stage)) continue;
150	    if (isStageReady(s, stage)) return stage;
151	    return "processing";
152	  }
153	
154	  return "chat";
155	}
156	
157	/**
158	 * Live progress message for the deepest still-running pipeline stage, or
159	 * `null` if none have emitted yet. Used by the writing-style reveal's
160	 * holding block while we wait for todos.
161	 */
162	const POST_WRITING_PROGRESS_STAGES: readonly OnboardingStage[] = [
163	  "workflows_creating",
164	  "todos_creating",
165	  "triage_analyzing",
166	];
167	
168	export function getCurrentProgress(s: OnboardingState): string | null {
169	  for (const stage of POST_WRITING_PROGRESS_STAGES) {
170	    const value = s.progressByStage[stage];
171	    if (value) return value;
172	  }
173	  return null;
174	}
175	
176	/** Step index per stage for the top progress bar; total is PROGRESS_TOTAL_STEPS. */
177	const STAGE_PROGRESS: Record<Stage, number> = {
178	  questions: 0,
179	  focus: 3,
180	  processing: 3,
181	  revealWriting: 4,
182	  revealTodos: 5,
183	  workflows: 6,
184	  platforms: 7,
185	  chat: 8,
186	};
187	
188	export const PROGRESS_TOTAL_STEPS = 8;
189	
190	/** Step index (0-based) for the top progress bar. Snaps to 0 during restart. */
191	export function getProgress(s: OnboardingState, stage: Stage): number {
192	  if (s.isRestarting) return 0;
193	  if (stage === "questions") return s.questionIndex;
194	  return STAGE_PROGRESS[stage];
195	}
