@router.post("", response_model=OnboardingResponse)
async def complete_user_onboarding(
    onboarding_data: OnboardingRequest,
    background_tasks: BackgroundTasks,
    user: dict = Depends(get_current_user),
    tz_info: GET_USER_TZ_TYPE = Depends(get_user_timezone),
):
    """Complete user onboarding by storing preferences and queuing the intelligence pipeline."""
    log.set(
        user={"id": user["user_id"]},
        onboarding={
            "operation": "complete",
            "is_complete": True,
            "timezone": tz_info[0],
        },
    )

    try:
        # Check completion state BEFORE delegating, so we know whether this
        # call is the user's first submission (queue the pipeline) or a
        # remount-induced replay (no-op the pipeline). complete_onboarding
        # also short-circuits when already completed; we just need the same
        # signal here to decide on enqueue.
        existing = await users_collection.find_one(
            {"_id": ObjectId(user["user_id"])},
            {"onboarding.completed": 1},
        )
        already_completed = bool(
            existing and (existing.get("onboarding") or {}).get("completed")
        )

        updated_user = await complete_onboarding(
            user["user_id"],
            onboarding_data,
            background_tasks,
        )

        if not already_completed:
            try:
                await enqueue_intelligence_job(user["user_id"])
            except Exception as e:
                log.error(f"Failed to queue intelligence task: {e}", exc_info=True)
        else:
            log.info(
                "[complete_user_onboarding] skipping intelligence enqueue, already completed",
                user_id=user["user_id"],
            )

        return OnboardingResponse(
            success=True, message="Onboarding completed successfully", user=updated_user

